      out.write("        /**\r\n");
      out.write("         * Exports HTML Table data directly into a CSV Spreadsheet.\r\n");
      out.write("         * Works natively in client web browser without server load.\r\n");
      out.write("         */\r\n");
      out.write("        function exportTableToCSV(tableId, filename) {\r\n");
      out.write("            var csv = [];\r\n");
      out.write("            var table = document.getElementById(tableId);\r\n");
      out.write("            if (!table) return;\r\n");
      out.write("\r\n");
      out.write("            var rows = table.querySelectorAll(\"tr\");\r\n");
      out.write("            \r\n");
      out.write("            for (var i = 0; i < rows.length; i++) {\r\n");
      out.write("                var row = [];\r\n");
      out.write("                var cols = rows[i].querySelectorAll(\"td, th\");\r\n");
      out.write("                \r\n");
      out.write("                // Skip the Actions column header and cell data if this is admin view\r\n");
      out.write("                var limit = cols.length;\r\n");
      out.write("                var isAdmin = \"");
      out.print( currentUser.getUserRole() );
      out.write("\" === \"ADMIN\";\r\n");
      out.write("                if (isAdmin && i > 0) {\r\n");
      out.write("                    limit = cols.length - 1; // skip last td (actions)\r\n");
      out.write("                } else if (isAdmin && i == 0) {\r\n");
      out.write("                    limit = cols.length - 1; // skip last th (actions)\r\n");
      out.write("                }\r\n");
      out.write("\r\n");
      out.write("                for (var j = 0; j < limit; j++) {\r\n");
      out.write("                    var cellText = cols[j].innerText.trim();\r\n");
      out.write("                    cellText = cellText.replace(/\"/g, '\"\"'); // Escape double quotes\r\n");
      out.write("                    row.push('\"' + cellText + '\"');\r\n");
      out.write("                }\r\n");
      out.write("                \r\n");
      out.write("                csv.push(row.join(\",\"));\r\n");
      out.write("            }\r\n");
      out.write("\r\n");
      out.write("            var csvFile = new Blob([csv.join(\"\\n\")], { type: \"text/csv;charset=utf-8;\" });\r\n");
      out.write("            var downloadLink = document.createElement(\"a\");\r\n");
      out.write("            \r\n");
      out.write("            downloadLink.download = filename;\r\n");
      out.write("            downloadLink.href = window.URL.createObjectURL(csvFile);\r\n");
      out.write("            downloadLink.style.display = \"none\";\r\n");
      out.write("            document.body.appendChild(downloadLink);\r\n");
      out.write("            downloadLink.click();\r\n");
      out.write("            document.body.removeChild(downloadLink);\r\n");
      out.write("        }\r\n");
      out.write("    </script>\r\n");
