      out.write("                    html += \"      <div class='detail-item'><strong>Order Number:</strong> \" + item.orderNumber + \"</div>\";\r\n");
      out.write("                    html += \"    </div>\";\r\n");
      out.write("                    html += \"  </div>\";\r\n");
      out.write("                    html += \"</div>\";\r\n");
